#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    (void)shadow;

    const int lid = get_local_id(0);
    if (lid != 0) return;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = i; j < BLOCK_SIZE; j++) {
            float v = m[(offset + i) * matrix_dim + (offset + j)];
            for (int k = 0; k < i; k++) {
                v -= m[(offset + i) * matrix_dim + (offset + k)] *
                     m[(offset + k) * matrix_dim + (offset + j)];
            }
            m[(offset + i) * matrix_dim + (offset + j)] = v;
        }

        float temp = 1.0f / m[(offset + i) * matrix_dim + (offset + i)];
        for (int j = i + 1; j < BLOCK_SIZE; j++) {
            float v = m[(offset + j) * matrix_dim + (offset + i)];
            for (int k = 0; k < i; k++) {
                v -= m[(offset + j) * matrix_dim + (offset + k)] *
                     m[(offset + k) * matrix_dim + (offset + i)];
            }
            m[(offset + j) * matrix_dim + (offset + i)] = v * temp;
        }
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    (void)dia;
    (void)peri_row;
    (void)peri_col;

    const int lid = get_local_id(0);
    if (lid != 0) return;

    const int chunk_idx = (int)get_group_id(0);

    float temp[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp[i * BLOCK_SIZE + j] =
                m[(offset + i) * matrix_dim + (offset + j)];
        }
    }

    int i_global = offset;
    int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += temp[i * BLOCK_SIZE + k] *
                       m[(i_global + k) * matrix_dim + (j_global + j)];
            }
            m[(i_global + i) * matrix_dim + (j_global + j)] -= sum;
        }
    }

    j_global = offset;
    i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += m[(i_global + i) * matrix_dim + (j_global + k)] *
                       temp[k * BLOCK_SIZE + j];
            }
            m[(i_global + i) * matrix_dim + (j_global + j)] =
                (m[(i_global + i) * matrix_dim + (j_global + j)] - sum) /
                m[(offset + j) * matrix_dim + (offset + j)];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    (void)peri_row;
    (void)peri_col;

    const int lx = get_local_id(0);
    const int ly = get_local_id(1);
    if (lx != 0 || ly != 0) return;

    const int chunk_col = (int)get_group_id(0);
    const int chunk_row = (int)get_group_id(1);

    const int i_global = offset + BLOCK_SIZE * (1 + chunk_row);
    const int j_global = offset + BLOCK_SIZE * (1 + chunk_col);

    float temp_top[BLOCK_SIZE * BLOCK_SIZE];
    float temp_left[BLOCK_SIZE * BLOCK_SIZE];
    float sum[BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] =
                m[(offset + i) * matrix_dim + (j_global + j)];
            temp_left[i * BLOCK_SIZE + j] =
                m[(i_global + i) * matrix_dim + (offset + j)];
        }
    }

    for (int j = 0; j < BLOCK_SIZE; j++) sum[j] = 0.0f;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int k = 0; k < BLOCK_SIZE; k++) {
            const float lv = temp_left[i * BLOCK_SIZE + k];
            for (int j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += lv * temp_top[k * BLOCK_SIZE + j];
            }
        }
        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[(i_global + i) * matrix_dim + (j_global + j)] -= sum[j];
            sum[j] = 0.0f;
        }
    }
}
